const payload = $json || {};
const ready = payload.ready === true || payload.context?.ready === true;
const reason = String(
  payload.reason ||
  payload.context?.reason ||
  payload.error?.message ||
  payload.message ||
  (ready ? 'Session ready.' : 'Worker session is not ready.')
).trim();

return [{
  json: {
    ready,
    reason,
    context: payload.context && typeof payload.context === 'object'
      ? payload.context
      : $('Config').first().json,
  },
}];

const err = $json?.error;
const message = String(
  $json?.reason ||
  (typeof err === 'string' ? err : err?.message) ||
  $json?.message ||
  'Session check failed.'
).trim();

return [{
  json: {
    status: 'Failed',
    failed_stage: 'session_check',
    error_message: message,
    operator_action: `Session check failed: ${message}`,
    updated_at: new Date().toISOString(),
  },
}];

const payload = $json || {};
const err = payload.error;
if (err) {
  throw new Error(typeof err === 'string' ? err : (err.message || JSON.stringify(err)));
}
const context = payload.context && typeof payload.context === 'object'
  ? payload.context
  : null;
if (!context) throw new Error('Stage 1 response did not contain a context object.');
if (!context.lead?.email) throw new Error('Stage 1 context lost lead.email.');

const status = String(context.status || '').trim().toLowerCase();
if (status === 'failed' || status === 'error') {
  throw new Error(String(context.operator_action || context.reason || 'Stage 1 returned failed status.'));
}

const stage = context.stage1;
if (!stage || typeof stage !== 'object') {
  throw new Error('Stage 1 response did not contain context.stage1.');
}
const hasOutput = [stage.responseText, stage.mdPath, stage.path, stage.filePath, stage.output]
  .some(v => String(v ?? '').trim() !== '');
if (!hasOutput) throw new Error('Stage 1 completed without a usable output or artifact path.');

return [{ json: {
  ...context,
  status: 'Processing',
  stage1_status: 'completed',
  updated_at: new Date().toISOString(),
} }];

const payload = $json || {};
const err = payload.error;
if (err) {
  throw new Error(typeof err === 'string' ? err : (err.message || JSON.stringify(err)));
}
const context = payload.context && typeof payload.context === 'object'
  ? payload.context
  : null;
if (!context) throw new Error('Stage 2 response did not contain a context object.');
if (!context.lead?.email) throw new Error('Stage 2 context lost lead.email.');

const status = String(context.status || '').trim().toLowerCase();
if (status === 'failed' || status === 'error') {
  throw new Error(String(context.operator_action || context.reason || 'Stage 2 returned failed status.'));
}

const stage = context.stage2;
if (!stage || typeof stage !== 'object') {
  throw new Error('Stage 2 response did not contain context.stage2.');
}
const hasOutput = [stage.responseText, stage.mdPath, stage.path, stage.filePath, stage.output]
  .some(v => String(v ?? '').trim() !== '');
if (!hasOutput) throw new Error('Stage 2 completed without a usable output or artifact path.');

return [{ json: {
  ...context,
  status: 'Processing',
  stage2_status: 'completed',
  updated_at: new Date().toISOString(),
} }];

const payload = $json || {};
const err = payload.error;
if (err) {
  throw new Error(typeof err === 'string' ? err : (err.message || JSON.stringify(err)));
}
const context = payload.context && typeof payload.context === 'object'
  ? payload.context
  : null;
if (!context) throw new Error('Stage 3 response did not contain a context object.');
if (!context.lead?.email) throw new Error('Stage 3 context lost lead.email.');

const status = String(context.status || '').trim().toLowerCase();
if (status === 'failed' || status === 'error') {
  throw new Error(String(context.operator_action || context.reason || 'Stage 3 returned failed status.'));
}

const stage = context.stage3;
if (!stage || typeof stage !== 'object') {
  throw new Error('Stage 3 response did not contain context.stage3.');
}
const hasOutput = [stage.responseText, stage.mdPath, stage.path, stage.filePath, stage.output]
  .some(v => String(v ?? '').trim() !== '');
if (!hasOutput) throw new Error('Stage 3 completed without a usable output or artifact path.');

return [{ json: {
  ...context,
  status: 'Processing',
  stage3_status: 'completed',
  updated_at: new Date().toISOString(),
} }];

// Select up to Config.batch_size eligible leads. Status and email comparisons are normalized.
const cfg = $('Config').first().json;
const str = (v) => (v === null || v === undefined) ? '' : String(v);
const norm = (v) => str(v).trim().toLowerCase();
const normStatus = (v) => norm(v).replace(/[\s-]+/g, '_');
const normLi = (v) => norm(v).replace(/^https?:\/\/(www\.)?/, '').replace(/\/+$/, '');
const emailOkay = (v) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(str(v).trim());
const dateMs = (v) => {
  const ms = Date.parse(str(v));
  return Number.isFinite(ms) ? ms : 0;
};

const paused = cfg.paused === true || norm(cfg.paused) === 'true';
const batchSize = Math.max(1, Number(cfg.batch_size || 10));
const maxAttempts = Math.max(1, Number(cfg.max_attempts || 3));
const staleMs = Math.max(1, Number(cfg.processing_stale_minutes || 60)) * 60 * 1000;

let executionId = '';
try { executionId = str($execution.id); } catch (e) {}
const runId = executionId
  ? `exec_${executionId}`
  : `run_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;

if (paused) {
  return [{ json: {
    is_lead: false,
    no_work: true,
    reason: 'Pipeline is paused in Config.paused=true.',
    run_id: runId,
  } }];
}

const leadRows = $('Read Leads Tab').all().map(i => i.json || {});
if (!leadRows.length) {
  return [{ json: {
    is_lead: false,
    no_work: true,
    reason: 'Leads tab returned no rows.',
    run_id: runId,
  } }];
}

let trackerRows = [];
try {
  trackerRows = $('Read Tracker Sheet').all()
    .map(i => i.json || {})
    .filter(r => Object.values(r).some(v => str(v).trim() !== ''));
} catch (e) {}

// Keep the newest row for each normalized email if duplicate tracker rows exist.
const trackerByEmail = new Map();
for (const row of trackerRows) {
  const key = norm(row.email);
  if (!key) continue;
  const previous = trackerByEmail.get(key);
  if (!previous || dateMs(row.updated_at) >= dateMs(previous.updated_at)) {
    trackerByEmail.set(key, row);
  }
}

const TERMINAL = new Set([
  'draft_created',
  'skip',
  'do_not_contact',
  'unsubscribed',
  'manual_review',
  'draft_unverified',
]);
const doneEmail = new Set();
const doneLi = new Set();

for (const row of trackerByEmail.values()) {
  const status = normStatus(row.status);
  const attempts = Number(row.attempts || 0);
  const burnt = status === 'failed' && attempts >= maxAttempts;
  const processingIsFresh = status === 'processing' &&
    dateMs(row.updated_at) > 0 &&
    (Date.now() - dateMs(row.updated_at)) < staleMs;

  if (!TERMINAL.has(status) && !burnt && !processingIsFresh) continue;
  const email = norm(row.email);
  const linkedin = normLi(row.linkedinUrl || row.linkedin_url);
  if (email) doneEmail.add(email);
  if (linkedin) doneLi.add(linkedin);
}

const joinArr = (row, prefix) => {
  const values = [];
  for (let i = 0; i < 40; i++) {
    const value = str(row[`${prefix}/${i}`]).trim();
    if (value) values.push(value);
  }
  return values.join(', ');
};

const seenEmail = new Set();
const seenLi = new Set();
const out = [];

for (const raw of leadRows) {
  const row = {};
  for (const [key, value] of Object.entries(raw)) row[key] = str(value);

  const email = norm(row.email);
  if (!emailOkay(email)) continue;
  const linkedin = normLi(row.linkedinUrl);

  if (doneEmail.has(email) || seenEmail.has(email)) continue;
  if (linkedin && (doneLi.has(linkedin) || seenLi.has(linkedin))) continue;

  seenEmail.add(email);
  if (linkedin) seenLi.add(linkedin);

  const previous = trackerByEmail.get(email) || {};
  const attempts = Number(previous.attempts || 0) + 1;

  const lead = {
    ...row,
    email,
    name: row.fullName || [row.firstName, row.lastName].filter(Boolean).join(' ').trim() || email,
    title: row.position || row.title || '',
    organization_name: row.companyName || 'Unknown Company',
    organization_industry: joinArr(row, 'companyIndustry'),
    organization_size: row.companySizeRange || row.companySize || '',
    organization_founded_year: row.foundedYear || '',
    organization_description: row.companyDescription || '',
    organization_specialities: joinArr(row, 'companySpecialties'),
    organization_website: row.companyDomain || '',
    organization_linkedin: row.companyLinkedinUrl || '',
    linkedin_url: row.linkedinUrl || '',
    seniority: row.seniority || '',
    functional: row.functional || joinArr(row, 'functions'),
    phone_numbers: row.phone || '',
    all_emails: email,
    city: row.personCity || row.companyCity || '',
    state: row.personState || row.companyState || '',
    country: row.personCountry || row.companyCountry || '',
    annual_revenue: row.annualRevenue || '',
    total_funding: row.totalFunding || '',
    funding_stage: row.fundingStage || '',
    technologies: joinArr(row, 'technologies'),
    company_audience: row.companyAudience || '',
    email_status: row.emailStatus || '',
  };

  const provider = String(cfg.ai_provider || 'chatgpt');
  const workerUrl = String(cfg[`${provider}_worker_url`] || cfg.chatgpt_worker_url || '');

  out.push({ json: {
    is_lead: true,
    no_work: false,
    execution_id: executionId,
    run_id: runId,
    status: 'Fetched',
    operator_action: `Selected as lead ${out.length + 1}/${batchSize}.`,
    updated_at: new Date().toISOString(),
    attempts,
    lead,
    raw_apollo_json: JSON.stringify(lead),
    idempotency_key: email,
    worker_url: workerUrl,
    grok_worker_url: workerUrl,
  } });

  if (out.length >= batchSize) break;
}

if (!out.length) {
  return [{ json: {
    is_lead: false,
    no_work: true,
    reason: `No eligible leads. Leads rows=${leadRows.length}; Tracker rows=${trackerRows.length}; batch_size=${batchSize}; max_attempts=${maxAttempts}.`,
    run_id: runId,
    execution_id: executionId,
  } }];
}

return out;

const a3 = $('Adopt Stage 3 Context').item.json || $json || {};
const cfg = $('Config').first().json;
const lead = a3.lead || {};
const raw = String(a3.stage3?.responseText || a3.stage3?.output || '').trim();
const recipient = String(lead.email || '').trim().toLowerCase();

if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(recipient)) {
  throw new Error(`Invalid recipient email: ${recipient || 'missing'}`);
}
if (!raw) throw new Error('Stage 3 returned an empty final-email response.');

const subjectMatch = raw.match(/^\s*Subject:\s*(.+)$/im);
let subject = subjectMatch ? subjectMatch[1].trim() : '';
let body = raw;
if (subjectMatch) {
  const index = raw.indexOf(subjectMatch[0]) + subjectMatch[0].length;
  body = raw.slice(index).replace(/^\s*\r?\n/, '').trim();
} else {
  body = raw.replace(/^\s*To:.*$/im, '').trim();
}
body = body
  .replace(/^\s*Subject:.*$/im, '')
  .replace(/\n+\s*(Best|Regards|Sincerely),?\s*(\n[^\n]*)?\s*$/i, '')
  .trim();

if (!subject) subject = `Quick question about ${lead.organization_name || 'your company'}`;
let signature = String(cfg.email_signature || '').trim();
const unresolved = /\[(your name|your title|company|insert|name)\]|you@example\.com|<[^>]+>/i;
let emailWarning = '';
if (signature && unresolved.test(signature)) {
  emailWarning = 'Configured signature contained placeholders and was omitted. Update Config.email_signature before production use.';
  signature = '';
}
if (unresolved.test(subject) || unresolved.test(body)) {
  throw new Error('Generated email contains unresolved placeholder text.');
}
const emailBody = signature ? `${body}\n\n${signature}` : body;
const minChars = Math.max(20, Number(cfg.min_email_body_chars || 80));

if (subject.length < 3 || subject.length > 200) {
  throw new Error(`Email subject length is invalid (${subject.length} characters).`);
}
if (emailBody.length < minChars) {
  throw new Error(`Email body is too short (${emailBody.length} characters; minimum ${minChars}).`);
}
if (!body || (signature && emailBody.trim() === signature)) {
  throw new Error('Email body is empty or signature-only.');
}

return [{ json: {
  ...a3,
  email_subject: subject,
  email_body: emailBody,
  recipient,
  formatted_email_valid: true,
  email_warning: emailWarning,
} }];

const selected = $('Select Batch').all()
  .map(i => i.json || {})
  .filter(i => i.is_lead === true);
const expected = selected.length;
const norm = (v) => String(v ?? '').trim().toLowerCase();
const normStatus = (v) => norm(v).replace(/[\s-]+/g, '_');
const dateMs = (v) => {
  const ms = Date.parse(String(v ?? ''));
  return Number.isFinite(ms) ? ms : 0;
};

let rows = [];
try {
  rows = $('Read Batch Result Retry').all().map(i => i.json || {});
} catch (e) {}
if (!rows.length) {
  try { rows = $('Read Batch Result').all().map(i => i.json || {}); } catch (e) {}
}

const selectedByKey = new Map(selected.map(item => [
  `${norm(item.lead?.email)}|${String(item.run_id || '')}`,
  item,
]));

// Deduplicate by normalized email + current run ID, keeping the newest row.
const latest = new Map();
for (const row of rows) {
  const key = `${norm(row.email)}|${String(row.run_id || '')}`;
  if (!selectedByKey.has(key)) continue;
  const previous = latest.get(key);
  if (!previous || dateMs(row.updated_at) >= dateMs(previous.updated_at)) latest.set(key, row);
}

const results = [];
for (const [key, item] of selectedByKey.entries()) {
  const row = latest.get(key);
  results.push({
    email: norm(item.lead?.email),
    run_id: String(item.run_id || ''),
    status: row ? String(row.status || 'No Status') : 'Missing',
    normalized_status: row ? normStatus(row.status) : 'missing',
    operator_action: row ? String(row.operator_action || '') : 'No current-run Tracker row was visible.',
  });
}

const drafted = results.filter(r => r.normalized_status === 'draft_created').length;
const failed = results.filter(r => r.normalized_status === 'failed').length;
const manualReview = results.filter(r => ['manual_review', 'draft_unverified'].includes(r.normalized_status)).length;
const missing = results.filter(r => r.normalized_status === 'missing').length;
const other = results.filter(r => ![
  'draft_created', 'failed', 'manual_review', 'draft_unverified', 'missing'
].includes(r.normalized_status)).length;

let outcome = 'success';
if (missing > 0 || other > 0) outcome = 'consistency_error';
else if (drafted === expected && expected > 0) outcome = 'success';
else if (drafted > 0) outcome = 'warning';
else outcome = 'error';

const summary = `Batch: ${drafted} drafted, ${failed} failed, ${manualReview} manual review, ${missing} missing (of ${expected} leads).`;
const details = results
  .filter(r => r.normalized_status !== 'draft_created')
  .map(r => `${r.email}: ${r.status}${r.operator_action ? ` — ${r.operator_action}` : ''}`);

return [{ json: {
  outcome,
  expected,
  drafted,
  failed,
  manual_review: manualReview,
  missing,
  other,
  summary,
  details,
  error_message: details.length ? summary + ' | ' + details.join(' | ') : summary,
  results,
} }];

const items = $input.all();
const fe = $('Format Email').item.json;
const cfg = $('Config').first().json;
const maxFiles = Math.max(0, Number(cfg.max_attachment_files || 5));
const maxBytes = Math.max(0, Number(cfg.max_attachment_total_bytes || 20000000));
const allowed = new Set(String(cfg.allowed_attachment_extensions || '')
  .split(',').map(v => v.trim().toLowerCase()).filter(Boolean));

const binary = {};
const warnings = [];
let count = 0;
let totalBytes = 0;

for (const item of items) {
  if (!item.binary) {
    if (item.json?.error?.message || item.json?.message) {
      warnings.push(`Attachment read skipped: ${item.json?.error?.message || item.json?.message}`);
    }
    continue;
  }
  for (const key of Object.keys(item.binary)) {
    const file = item.binary[key] || {};
    const fileName = String(file.fileName || file.fileName || `attachment_${count}`);
    const ext = fileName.includes('.') ? fileName.split('.').pop().toLowerCase() : '';
    const size = Number(file.fileSize || file.fileSizeBytes || 0);

    if (allowed.size && ext && !allowed.has(ext)) {
      warnings.push(`Skipped disallowed attachment: ${fileName}`);
      continue;
    }
    if (count >= maxFiles) {
      warnings.push(`Skipped ${fileName}: maximum attachment count ${maxFiles} reached.`);
      continue;
    }
    if (size > 0 && totalBytes + size > maxBytes) {
      warnings.push(`Skipped ${fileName}: attachment size limit would be exceeded.`);
      continue;
    }
    binary[`attachment_${count}`] = file;
    count++;
    totalBytes += Math.max(0, size);
  }
}

const out = {
  json: {
    ...fe,
    attachment_count: count,
    attachment_total_bytes: totalBytes,
    attachment_warning: warnings.join(' | '),
  },
};
if (count > 0) out.binary = binary;
return [out];

const loop = $('Loop Over Items').item.json || {};
const current = $json || {};
const clean = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v === 'object') {
    try { return JSON.stringify(v); } catch (e) { return String(v); }
  }
  return String(v);
};
const clip = (v, max = 4000) => clean(v).slice(0, max);
const stageValue = (stage) => {
  if (!stage || typeof stage !== 'object') return '';
  return clip(stage.mdPath || stage.path || stage.filePath || stage.responseText || stage.output || stage);
};

let a1 = {}, a2 = {}, a3 = {}, formatted = {}, created = {};
try { a1 = $('Adopt Stage 1 Context').item.json || {}; } catch (e) {}
try { a2 = $('Adopt Stage 2 Context').item.json || {}; } catch (e) {}
try { a3 = $('Adopt Stage 3 Context').item.json || {}; } catch (e) {}
try { formatted = $('Format Email').item.json || {}; } catch (e) {}
try { created = $('Preserve Draft Creation').item.json || {}; } catch (e) {}

const lead = current.lead || a3.lead || a2.lead || a1.lead || loop.lead || {};
const status = clean(current.status || 'Failed').trim() || 'Failed';
const success = status.toLowerCase() === 'draft_created';
const errorMessage = clip(
  current.error_message ||
  (typeof current.error === 'string' ? current.error : current.error?.message) ||
  current.message ||
  ''
);

const gmailDraftId = clean(
  current.gmail_draft_id || created.gmail_draft_id || current.id || ''
);
const gmailMessageId = clean(
  current.gmail_message_id || created.gmail_message_id || current.messageId || ''
);

return [{ json: {
  email: clean(lead.email).trim().toLowerCase(),
  fullName: clean(lead.fullName || lead.name),
  companyName: clean(lead.companyName || lead.organization_name),
  companyLinkedinUrl: clean(lead.companyLinkedinUrl || lead.organization_linkedin),
  linkedinUrl: clean(lead.linkedinUrl || lead.linkedin_url),
  position: clean(lead.position || lead.title),
  emailStatus: clean(lead.emailStatus || lead.email_status),
  rowType: clean(lead.rowType || 'tracker'),

  status,
  operator_action: clip(current.operator_action || (success
    ? 'Draft created and verified. Review in Gmail before sending.'
    : `Pipeline failed: ${errorMessage || 'Unknown error'}`)),
  failed_stage: clean(current.failed_stage),
  error_code: clean(current.error_code),
  error_message: errorMessage,
  retryable: clean(current.retryable ?? (!success)),
  draft_may_exist: clean(current.draft_may_exist ?? Boolean(gmailDraftId)),
  gmail_verified: clean(current.gmail_verified ?? success),

  run_id: clean(current.run_id || a3.run_id || a2.run_id || a1.run_id || loop.run_id),
  execution_id: clean(current.execution_id || loop.execution_id),
  processing_started_at: clean(current.processing_started_at || loop.processing_started_at),
  updated_at: clean(current.updated_at || new Date().toISOString()),

  stage1: stageValue(a3.stage1 || a2.stage1 || a1.stage1),
  stage1_status: clean(a3.stage1_status || a2.stage1_status || a1.stage1_status || (a1.stage1 ? 'completed' : '')),
  stage1_error: clean(current.failed_stage === 'stage1_research' ? errorMessage : ''),
  stage2: stageValue(a3.stage2 || a2.stage2),
  stage2_status: clean(a3.stage2_status || a2.stage2_status || (a2.stage2 ? 'completed' : '')),
  stage2_error: clean(current.failed_stage === 'stage2_review' ? errorMessage : ''),
  stage3: stageValue(a3.stage3),
  stage3_status: clean(a3.stage3_status || (a3.stage3 ? 'completed' : '')),
  stage3_error: clean(current.failed_stage === 'stage3_final_email' ? errorMessage : ''),

  attempts: clean(loop.attempts || current.attempts || 1),
  idempotency_key: clean(loop.idempotency_key || current.idempotency_key || lead.email).trim().toLowerCase(),
  id: gmailDraftId || clean(current.id || ''),
  email_subject: clean(current.email_subject || created.email_subject || formatted.email_subject),
  recipient: clean(current.recipient || created.recipient || formatted.recipient || lead.email),
  gmail_draft_id: gmailDraftId,
  gmail_message_id: gmailMessageId,
  attachment_count: clean(current.attachment_count ?? created.attachment_count ?? formatted.attachment_count ?? 0),
  attachment_warning: clip(current.attachment_warning || created.attachment_warning || formatted.attachment_warning),
  email_warning: clip(current.email_warning || created.email_warning || formatted.email_warning),
  gmail_verification_warning: clip(current.gmail_verification_warning || created.gmail_verification_warning || formatted.gmail_verification_warning),
  verified_recipients: clip(current.verified_recipients || created.verified_recipients || ''),
} }];

return [{ json: {
  outcome: 'no_work',
  summary: String($json.reason || 'No eligible leads were available.'),
  run_id: $json.run_id || '',
  execution_id: $json.execution_id || '',
} }];

const loop = $('Loop Over Items').item.json || {};
const email = String(loop.lead?.email || '').trim().toLowerCase();
const runId = String(loop.run_id || '');
const rows = $input.all().map(i => i.json || {});
const norm = (v) => String(v ?? '').trim().toLowerCase();
const normStatus = (v) => norm(v).replace(/[\s-]+/g, '_');
const dateMs = (v) => {
  const ms = Date.parse(String(v ?? ''));
  return Number.isFinite(ms) ? ms : 0;
};

const matches = rows.filter(r => norm(r.email) === email);
const latest = matches.sort((a, b) => dateMs(b.updated_at) - dateMs(a.updated_at))[0] || {};
const claim_ok = normStatus(latest.status) === 'processing' && String(latest.run_id || '') === runId;

return [{ json: {
  ...loop,
  claim_ok,
  processing_started_at: String(latest.processing_started_at || loop.processing_started_at || ''),
  claim_reason: claim_ok
    ? 'Processing claim verified.'
    : `Processing claim was not owned by this execution. Tracker run_id=${String(latest.run_id || 'missing')}; status=${String(latest.status || 'missing')}.`,
} }];

const loop = $('Loop Over Items').item.json || {};
return [{ json: {
  ...loop,
  status: 'Claim_Conflict',
  failed_stage: 'processing_claim',
  operator_action: String($json.claim_reason || 'Processing claim conflict; lead was not processed.'),
  updated_at: new Date().toISOString(),
} }];

const loop = $('Loop Over Items').item.json || {};
const payload = $json || {};
const err = payload.error;
if (err) {
  throw new Error(typeof err === 'string' ? err : (err.message || JSON.stringify(err)));
}
if (String(payload.status || '').trim().toLowerCase() === 'failed') {
  throw new Error(String(payload.reason || payload.message || 'New chat worker returned failed status.'));
}

const incoming = payload.context && typeof payload.context === 'object'
  ? payload.context
  : {};
const merged = {
  ...loop,
  ...incoming,
  lead: incoming.lead || loop.lead,
  run_id: incoming.run_id || loop.run_id,
  execution_id: incoming.execution_id || loop.execution_id,
  idempotency_key: incoming.idempotency_key || loop.idempotency_key,
