const verified = $json || {};
const created = $('Preserve Draft Creation').item.json || {};
const expectedSubject = String(created.email_subject || '').trim();
const expectedRecipient = String(created.recipient || '').trim().toLowerCase();
const expectedBody = String(created.email_body || '').trim();

const extractEmailsFromString = (value) => {
  const matches = String(value || '').toLowerCase().match(/[a-z0-9.!#$%&'*+\/=?^_`{|}~-]+@[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?(?:\.[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?)+/g);
  return matches || [];
};

const collectEmails = (value, depth) => {
  depth = depth || 0;
  if (depth > 5 || value === null || value === undefined) return [];
  if (typeof value === 'string' || typeof value === 'number') {
    return extractEmailsFromString(value);
  }
  if (Array.isArray(value)) {
    let out = [];
    for (const entry of value) out = out.concat(collectEmails(entry, depth + 1));
    return out;
  }
  if (typeof value === 'object') {
    let out = [];
    const addressKeys = ['address', 'value', 'text', 'html', 'email', 'emailAddress'];
    for (const key of addressKeys) {
      if (Object.prototype.hasOwnProperty.call(value, key)) {
        out = out.concat(collectEmails(value[key], depth + 1));
      }
    }
    return out;
  }
  return [];
};

const headerValue = (name) => {
  const target = String(name || '').toLowerCase();
  const candidates = [
    verified.headers,
    verified.message && verified.message.headers,
    verified.payload && verified.payload.headers,
    verified.message && verified.message.payload && verified.message.payload.headers,
  ];

  for (const headers of candidates) {
    if (!headers) continue;
    if (Array.isArray(headers)) {
      const found = headers.find((h) => String((h && h.name) || '').toLowerCase() === target);
      if (found && found.value !== undefined) return String(found.value || '');
      continue;
    }
    if (typeof headers === 'object') {
      for (const key of Object.keys(headers)) {
        if (String(key).toLowerCase() === target) return String(headers[key] || '');
      }
    }
  }
  return '';
};

const actualId = String(
  verified.id ||
  verified.draftId ||
  verified.draft_id ||
  created.gmail_draft_id ||
  ''
).trim();
if (!actualId) throw new Error('Gmail verification returned no draft ID.');
if (created.gmail_draft_id && actualId !== String(created.gmail_draft_id)) {
  throw new Error('Verified Gmail draft ID does not match the created draft ID.');
}

const actualSubject = String(
  verified.subject ||
  (verified.message && verified.message.subject) ||
  headerValue('subject') ||
  ''
).trim();

let actualRecipients = [];
const recipientSources = [
  verified.to,
  verified.recipient,
  verified.recipients,
  verified.message && verified.message.to,
  verified.message && verified.message.recipient,
  headerValue('to'),
];
for (const source of recipientSources) {
  actualRecipients = actualRecipients.concat(collectEmails(source, 0));
}
actualRecipients = Array.from(new Set(actualRecipients.map((v) => String(v).trim().toLowerCase()).filter(Boolean)));

const actualBody = String(
  verified.text ||
  verified.body ||
  verified.textAsHtml ||
  verified.html ||
  (verified.message && (verified.message.text || verified.message.body || verified.message.html)) ||
  ''
).trim();

const normalizeText = (value) => String(value || '')
  .replace(/\r\n/g, '\n')
  .replace(/[ \t]+\n/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

if (actualSubject && expectedSubject && normalizeText(actualSubject) !== normalizeText(expectedSubject)) {
  throw new Error('Verified Gmail draft subject does not match the generated subject.');
}

if (actualRecipients.length && expectedRecipient && !actualRecipients.includes(expectedRecipient)) {
  throw new Error(
    'Verified Gmail draft recipient does not match the selected lead. ' +
    'Expected=' + expectedRecipient + '; actual=' + actualRecipients.join(', ')
  );
}

const actualBodyNormalized = normalizeText(actualBody);
const expectedBodyNormalized = normalizeText(expectedBody);
if (
  actualBodyNormalized &&
  expectedBodyNormalized &&
  actualBodyNormalized !== expectedBodyNormalized &&
  actualBodyNormalized.indexOf(expectedBodyNormalized) === -1 &&
  expectedBodyNormalized.indexOf(actualBodyNormalized) === -1
) {
  throw new Error('Verified Gmail draft body does not match the generated email body.');
}

const verificationWarnings = [];
if (!actualRecipients.length) {
  verificationWarnings.push('Gmail returned the draft but did not expose a parseable To address; draft ID, subject and body checks passed.');
}
if (!actualSubject) verificationWarnings.push('Gmail returned no parseable subject for comparison.');
if (!actualBody) verificationWarnings.push('Gmail returned no parseable body for comparison.');

return [{ json: {
  ...created,
  verified_draft_response: verified,
  verified_recipients: actualRecipients,
  gmail_verification_warning: verificationWarnings.join(' '),
  gmail_verified: true,
  gmail_draft_id: created.gmail_draft_id || actualId,
  gmail_message_id: created.gmail_message_id || String(verified.messageId || verified.message_id || ''),
} }];

