if (!provider) problems.push('Config.ai_provider is missing.');
if (!workerUrl || !/^https?:\/\//i.test(workerUrl)) problems.push(`Worker URL for provider "${provider || 'missing'}" is invalid.`);
if (!String(cfg.sheet_id || '').trim()) problems.push('Config.sheet_id is missing.');
if (!String(cfg.leads_tab || '').trim()) problems.push('Config.leads_tab is missing.');
